import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import FilterPanel from './components/FilterPanel';
import StatsPanel from './components/StatsPanel';
import DonorList from './components/DonorList';

const App = () => {
  const [donors, setDonors] = useState([]);
  const [filteredDonors, setFilteredDonors] = useState([]);
  const [filters, setFilters] = useState({ bloodType: '', location: '' });

  useEffect(() => {
    // Mock data for donors
    const mockDonors = [
      { id: 1, name: 'John Doe', bloodType: 'A+', location: 'New York', phone: '123-456-7890', lastDonation: '2023-01-15' },
      { id: 2, name: 'Jane Smith', bloodType: 'O-', location: 'Los Angeles', phone: '987-654-3210', lastDonation: '2023-02-20' },
      { id: 3, name: 'Bob Johnson', bloodType: 'B+', location: 'Chicago', phone: '555-123-4567', lastDonation: '2023-03-10' },
      { id: 4, name: 'Alice Brown', bloodType: 'AB-', location: 'Houston', phone: '444-567-8901', lastDonation: '2023-04-05' },
      { id: 5, name: 'Charlie Wilson', bloodType: 'A-', location: 'Phoenix', phone: '333-789-0123', lastDonation: '2023-05-12' },
      { id: 6, name: 'Diana Lee', bloodType: 'O+', location: 'Philadelphia', phone: '222-345-6789', lastDonation: '2023-06-18' },
    ];
    setDonors(mockDonors);
    setFilteredDonors(mockDonors);
  }, []);

  useEffect(() => {
    let filtered = donors;
    if (filters.bloodType) {
      filtered = filtered.filter(donor => donor.bloodType === filters.bloodType);
    }
    if (filters.location) {
      filtered = filtered.filter(donor => donor.location.toLowerCase().includes(filters.location.toLowerCase()));
    }
    setFilteredDonors(filtered);
  }, [donors, filters]);

  const handleFilterChange = (newFilters) => {
    setFilters(newFilters);
  };

  return (
    <div className="app">
      <Header />
      <FilterPanel filters={filters} onFilterChange={handleFilterChange} />
      <StatsPanel totalDonors={donors.length} filteredDonors={filteredDonors.length} />
      <DonorList donors={filteredDonors} />
    </div>
  );
};

export default App;
